example_3_multi_document_complex.command:
const session = db.getMongo().startSession();
session.startTransaction();

// Calculate new GPA (simplified)
let newGpa = 3.92;

// Update student GPA
db.students.updateOne(
  { studentId: '20260001' },
  { $set: { gpa: newGpa } },
  { session: session }
);

// Insert grade record
db.grades.insertOne(
  { studentId: '20260001', courseId: 'CS101', grade: 'A', gpa: newGpa },
  { session: session }
);

session.commitTransaction();

example_4_scholarship_transfer.command:
const session = db.getMongo().startSession();
session.startTransaction();

try {
  // Reduce donor scholarship
  db.students.updateOne(
    { studentId: '20260001' },
    { $inc: { 'scholarshipDetails.amount': -5000 } },
    { session: session }
  );

  // Increase recipient scholarship
  db.students.updateOne(
    { studentId: '20260002' },
    { $inc: { 'scholarshipDetails.amount': 5000 } },
    { session: session }
  );

  // Log transaction
  db.auditLog.insertOne(
    { type: 'transfer', from: '20260001', to: '20260002', amount: 5000, date: new Date() },
    { session: session }
  );

  session.commitTransaction();
  console.log('Transfer successful');
} catch (error) {
  session.abortTransaction();
  console.log('Transfer failed, rolled back');
}

example_5_bulk_enrollment.command:
const session = db.getMongo().startSession();
session.startTransaction();

// Add course to student's courses array
db.students.updateOne(
  { studentId: '20260001' },
  { $push: { courses: 'DB301' } },
  { session: session }
);

// Create enrollment record
db.enrollments.insertOne(
  { studentId: '20260001', courseId: 'DB301', enrolledDate: new Date() },
  { session: session }
);

session.commitTransaction();
